/*
 * Sample Sort Implementation in MPI
 * Compile: mpicc sample_sort.c -o sample_sort
 * Run: mpirun -np 4 ./sample_sort
 */

#include <mpi.h>
#include <stdlib.h>
#include <stdio.h>
#include <string.h>

#define compare_int(a, b) ((*(int*)a) - (*(int*)b))

/* Function to select samples from sorted local data */
void select_samples(int *local_data, int local_count, int *samples, 
 int samples_per_proc, int num_procs) {
 for (int i = 0; i < samples_per_proc; i++) {
 int index = (i + 1) * local_count / (num_procs + 1);
 samples[i] = local_data[index];
 }
}

/* Function to partition data using splitters */
void partition_data(int *local_data, int local_count, int *splitters,
 int num_procs, int **partition_sizes, int ***partitions) {
 *partition_sizes = (int*)calloc(num_procs, sizeof(int));

 // First pass: count elements in each partition
 for (int i = 0; i < local_count; i++) {
 int bucket = 0;
 for (int j = 0; j < num_procs - 1; j++) {
 if (local_data[i] <= splitters[j]) break;
 bucket++;
 }
 (*partition_sizes)[bucket]++;
 }

 // Allocate partitions
 *partitions = (int**)malloc(num_procs * sizeof(int*));
 for (int i = 0; i < num_procs; i++) {
 if ((*partition_sizes)[i] > 0) {
 (*partitions)[i] = (int*)malloc((*partition_sizes)[i] * sizeof(int));
 } else {
 (*partitions)[i] = NULL;
 }
 }

 // Reset counters for second pass
 int *counters = (int*)calloc(num_procs, sizeof(int));

 // Second pass: distribute elements
 for (int i = 0; i < local_count; i++) {
 int bucket = 0;
 for (int j = 0; j < num_procs - 1; j++) {
 if (local_data[i] <= splitters[j]) break;
 bucket++;
 }
 (*partitions)[bucket][counters[bucket]++] = local_data[i];
 }
 free(counters);
}

int main(int argc, char *argv[]) {
 int rank, num_procs;
 int n = 16; // Total number of elements

 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &num_procs);

 if (n % num_procs != 0) {
 if (rank == 0) printf("Error: n must be divisible by num_procs\n");
 MPI_Finalize();
 return 1;
 }

 int local_count = n / num_procs;
 int *local_data = (int*)malloc(local_count * sizeof(int));
 int samples_per_proc = num_procs - 1;

 // Generate data at root and distribute
 if (rank == 0) {
 int *all_data = (int*)malloc(n * sizeof(int));
 printf("Original data: ");
 for (int i = 0; i < n; i++) {
 all_data[i] = (n - i); // Reverse order for testing
 printf("%d ", all_data[i]);
 }
 printf("\n");

 // Scatter data to all processes
 MPI_Scatter(all_data, local_count, MPI_INT, 
 local_data, local_count, MPI_INT, 0, MPI_COMM_WORLD);
 free(all_data);
 } else {
 MPI_Scatter(NULL, local_count, MPI_INT, 
 local_data, local_count, MPI_INT, 0, MPI_COMM_WORLD);
 }

 // Step 1: Local sort
 qsort(local_data, local_count, sizeof(int), compare_int);

 if (rank == 0) printf("After local sort:\n");
 MPI_Barrier(MPI_COMM_WORLD);
 for (int p = 0; p < num_procs; p++) {
 if (rank == p) {
 printf(" Process %d: ", rank);
 for (int i = 0; i < local_count; i++) printf("%d ", local_data[i]);
 printf("\n");
 }
 MPI_Barrier(MPI_COMM_WORLD);
 }

 // Step 2: Select samples
 int *samples = (int*)malloc(samples_per_proc * sizeof(int));
 select_samples(local_data, local_count, samples, samples_per_proc, num_procs);

 // Step 3: Gather samples at root
 int *all_samples = NULL;
 if (rank == 0) {
 all_samples = (int*)malloc(num_procs * samples_per_proc * sizeof(int));
 }
 MPI_Gather(samples, samples_per_proc, MPI_INT,
 all_samples, samples_per_proc, MPI_INT, 0, MPI_COMM_WORLD);

 // Step 4: Root determines splitters
 int *splitters = (int*)malloc((num_procs - 1) * sizeof(int));
 if (rank == 0) {
 qsort(all_samples, num_procs * samples_per_proc, sizeof(int), compare_int);
 for (int i = 0; i < num_procs - 1; i++) {
 splitters[i] = all_samples[(i + 1) * samples_per_proc];
 }
 printf("Splitters: ");
 for (int i = 0; i < num_procs - 1; i++) printf("%d ", splitters[i]);
 printf("\n");
 }

 // Step 5: Broadcast splitters
 MPI_Bcast(splitters, num_procs - 1, MPI_INT, 0, MPI_COMM_WORLD);

 // Step 6: Partition local data
 int *partition_sizes;
 int **partitions;
 partition_data(local_data, local_count, splitters, num_procs, 
 &partition_sizes, &partitions);

 // Step 7: All-to-all exchange
 int *send_counts = partition_sizes;
 int *recv_counts = (int*)malloc(num_procs * sizeof(int));
 MPI_Alltoall(send_counts, 1, MPI_INT, recv_counts, 1, MPI_INT, MPI_COMM_WORLD);

 // Calculate total received and prepare receive buffer
 int total_recv = 0;
 for (int i = 0; i < num_procs; i++) total_recv += recv_counts[i];
 int *recv_data = (int*)malloc(total_recv * sizeof(int));

 // Prepare send displacements
 int *sdispls = (int*)malloc(num_procs * sizeof(int));
 int *rdispls = (int*)malloc(num_procs * sizeof(int));
 sdispls[0] = rdispls[0] = 0;
 for (int i = 0; i < num_procs; i++) {
 if (i > 0) {
 sdispls[i] = sdispls[i-1] + send_counts[i-1];
 rdispls[i] = rdispls[i-1] + recv_counts[i-1];
 }
 }

 // Flatten send data
 int *send_data = (int*)malloc(local_count * sizeof(int));
 int send_idx = 0;
 for (int i = 0; i < num_procs; i++) {
 for (int j = 0; j < partition_sizes[i]; j++) {
 send_data[send_idx++] = partitions[i][j];
 }
 }

 // All-to-allv for variable-sized messages
 MPI_Alltoallv(send_data, send_counts, sdispls, MPI_INT,
 recv_data, recv_counts, rdispls, MPI_INT, MPI_COMM_WORLD);

 // Step 8: Final local sort
 qsort(recv_data, total_recv, sizeof(int), compare_int);

 // Step 9: Gather sorted data at root
 int *gather_counts = (int*)malloc(num_procs * sizeof(int));
 MPI_Gather(&total_recv, 1, MPI_INT, gather_counts, 1, MPI_INT, 0, MPI_COMM_WORLD);

 int *gather_displs = (int*)malloc(num_procs * sizeof(int));
 if (rank == 0) {
 gather_displs[0] = 0;
 for (int i = 1; i < num_procs; i++) {
 gather_displs[i] = gather_displs[i-1] + gather_counts[i-1];
 }
 }

 int *final_result = NULL;
 if (rank == 0) {
 final_result = (int*)malloc(n * sizeof(int));
 }

 MPI_Gatherv(recv_data, total_recv, MPI_INT,
 final_result, gather_counts, gather_displs, MPI_INT, 0, MPI_COMM_WORLD);

 // Print result
 if (rank == 0) {
 printf("\nSorted result: ");
 for (int i = 0; i < n; i++) {
 printf("%d ", final_result[i]);
 }
 printf("\n");
 free(final_result);
 }

 // Cleanup
 free(local_data);
 free(samples);
 free(splitters);
 free(partition_sizes);
 for (int i = 0; i < num_procs; i++) {
 if (partitions[i]) free(partitions[i]);
 }
 free(partitions);
 free(send_data);
 free(recv_data);
 free(send_counts);
 free(recv_counts);
 free(sdispls);
 free(rdispls);
 free(gather_counts);
 free(gather_displs);
 if (rank == 0) free(all_samples);

 MPI_Finalize();
 return 0;
}
